INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (2, 3.099, 2, 190801, "カリン", -416.5, 0.0, "2030/01/01 14:59:59", 20026, "2022/04/18 15:00:00", 1, "ミッションをクリアして、\n報酬をゲットしましょう！", 53, 20026002);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (2, 2.801, 3, 190801, "カリン", -416.5, 0.0, "2030/01/01 14:59:59", 20026, "2022/04/18 15:00:00", 1, "受け取ることができる\n報酬があるようです\n確認してみてください", 54, 20026003);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (2, 0.0, 4, 190801, "カリン", -416.5, 0.0, "2030/01/01 14:59:59", 20026, "2022/04/18 15:00:00", 2, "報酬がもらえますよ！\nチェックしてみてください", 54, 20026004);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (1, 0.0, 5, 190801, "カリン", -416.5, 0.0, "2030/01/01 14:59:59", 20026, "2022/04/18 15:00:00", 1, "イベントお疲れ様です！\n皆さんのご活躍ぶりには\nいつも感謝しています", 57, 20026005);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (2, 5.506, 1, 190801, "カリン", -363.0, 0.0, "2030/01/01 14:59:59", 20026, "2022/04/18 15:00:00", 1, "ギルド管理協会です！\n討伐証をお持ちでしたら、\n報酬交換できますよ", 55, 20026006);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (1, 1.216, 2, 190801, "カリン", -363.0, 0.0, "2030/01/01 14:59:59", 20026, "2022/04/18 15:00:00", 2, "お疲れ様です！\nここでは、討伐証と報酬を\n交換することができます！", 55, 20026007);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (1, 1.539, 3, 190801, "カリン", -363.0, 0.0, "2030/01/01 14:59:59", 20026, "2022/04/18 15:00:00", 2, "お疲れ様でした\n討伐証の交換、\nお忘れないように！", 56, 20026008);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (1, 1.875, 4, 190801, "カリン", -363.0, 0.0, "2030/01/01 14:59:59", 20026, "2022/04/18 15:00:00", 2, "終わっちゃいましたねー\n討伐証は努力の証！\n報酬と交換しましょう！", 56, 20026009);
